INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('safinah', 1, 'Muqaddimah & Rukun Islam', 'مُقَدِّمَةٌ وَأَرْكَانُ الإِسْلَامِ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, 'Rukun Islam', 'أَرْكَانُ الإِسْلَامِ', 'أَرْكَانُ الإِسْلَامِ خَمْسَةٌ: شَهَادَةُ أَنْ لَا إِلَهَ إِلَّا اللهُ وَأَنَّ مُحَمَّدًا رَسُوْلُ اللهِ، وَإِقَامُ الصَّلَاةِ، وَإِيْتَاءُ الزَّكَاةِ، وَصَوْمُ رَمَضَانَ، وَحِجُّ الْبَيْتِ لِمَنِ اسْتَطَاعَ إِلَيْهِ سَبِيْلًا.', 'Rukun Islam ada lima: (1) Bersaksi tiada Tuhan selain Allah dan Muhammad utusan-Nya, (2) Mendirikan shalat, (3) Menunaikan zakat, (4) Puasa Ramadhan, (5) Haji bagi yang mampu.', 'Lima rukun Islam ini fondasi agama. Syahadat adalah ikrar iman, shalat adalah tiang agama, zakat adalah pembersih harta, puasa adalah perisai dari hawa nafsu, dan haji adalah penyempurna Islam. Hadits Jibril menjadi dalil utamanya.', '[{"s":2,"v":183,"label":"Perintah Puasa"},{"s":3,"v":97,"label":"Kewajiban Haji"}]', '["bukhari:8"]' FROM pesantren_bab WHERE kitab_slug = 'safinah' AND bab_order = 1;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 2, 'Rukun Iman', 'أَرْكَانُ الإِيْمَانِ', 'أَرْكَانُ الإِيْمَانِ سِتَّةٌ: أَنْ تُؤْمِنَ بِاللهِ، وَمَلَائِكَتِهِ، وَكُتُبِهِ، وَرُسُلِهِ، وَالْيَوْمِ الْآخِرِ، وَبِالْقَدَرِ خَيْرِهِ وَشَرِّهِ مِنَ اللهِ تَعَالَى.', 'Rukun Iman ada enam: (1) Iman kepada Allah, (2) Malaikat, (3) Kitab-kitab, (4) Para Rasul, (5) Hari Akhir, (6) Takdir baik dan buruk dari Allah.', 'Enam rukun iman adalah pokok kepercayaan Islam. Iman kepada takdir bukan berarti pasrah tanpa usaha, melainkan keyakinan bahwa semua yang terjadi dalam batas ketentuan Allah, sementara manusia tetap punya ikhtiar dan tanggung jawab.', '[{"s":2,"v":285,"label":"Iman kepada Allah & Rasul"}]', '["muslim:8"]' FROM pesantren_bab WHERE kitab_slug = 'safinah' AND bab_order = 1;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('safinah', 2, 'Thaharah', 'بَابُ الطَّهَارَةِ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, 'Pembagian Air', 'أَقْسَامُ الْمِيَاهِ', 'الْمِيَاهُ الَّتِيْ يَجُوْزُ بِهَا التَّطَهُّرُ أَرْبَعَةٌ: مَاءُ السَّمَاءِ، وَمَاءُ الْبَحْرِ، وَمَاءُ النَّهْرِ، وَمَاءُ الْبِئْرِ.', 'Air yang boleh untuk bersuci ada empat: (1) Air hujan, (2) Air laut, (3) Air sungai/danau, (4) Air sumur.', 'Keempat jenis air ini adalah air muthlaq (suci menyucikan). Air dibagi: muthlaq (sah bersuci), musta''mal (bekas bersuci — suci tidak menyucikan), dan mutanajjis (terkena najis — tidak boleh). Air yang banyak (2 qullah/±190L) tidak najis kecuali berubah rasa/warna/bau.', NULL, '["abudawud:83"]' FROM pesantren_bab WHERE kitab_slug = 'safinah' AND bab_order = 2;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 2, 'Najis & Tingkatannya', 'النَّجَاسَةُ وَأَقْسَامُهَا', 'النَّجَاسَاتُ ثَلَاثَةٌ: الْمُغَلَّظَةُ — نَجَاسَةُ الْكَلْبِ وَالْخِنْزِيْرِ، تُغْسَلُ سَبْعَ مَرَّاتٍ إِحْدَاهَا بِالتُّرَابِ. وَالْمُخَفَّفَةُ — بَوْلُ الصَّبِيِّ الرَّضِيْعِ، يَكْفِيْ نَضْحُهُ. وَالْمُتَوَسِّطَةُ — سَائِرُ النَّجَاسَاتِ، تُغْسَلُ حَتَّى تَزُوْلَ.', 'Najis ada 3 tingkat: (1) Mughallazhah — anjing & babi, cuci 7x salah satunya dengan tanah. (2) Mukhaffafah — kencing bayi laki-laki yang hanya ASI, cukup diperciki air. (3) Mutawassithah — najis lainnya, cuci hingga hilang warna/bau/rasa.', 'Pembagian ini berdasarkan nash dan ijtihad ulama Syafi''iyyah. Penyucian dengan tanah untuk anjing terbukti ilmiah karena tanah mengandung mineral pembunuh bakteri tertentu. Perbedaan bayi laki-laki dan perempuan berdasar hadits shahih dari Nabi ﷺ.', NULL, '["muslim:279"]' FROM pesantren_bab WHERE kitab_slug = 'safinah' AND bab_order = 2;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 3, 'Fardhu Wudhu (6)', 'فَرَائِضُ الْوُضُوْءِ', 'فَرَائِضُ الْوُضُوْءِ سِتَّةٌ: النِّيَّةُ، وَغَسْلُ الْوَجْهِ، وَغَسْلُ الْيَدَيْنِ مَعَ الْمِرْفَقَيْنِ، وَمَسْحُ بَعْضِ الرَّأْسِ، وَغَسْلُ الرِّجْلَيْنِ مَعَ الْكَعْبَيْنِ، وَالتَّرْتِيْبُ.', 'Fardhu wudhu 6: (1) Niat, (2) Basuh wajah, (3) Basuh tangan s/d siku, (4) Usap sebagian kepala, (5) Basuh kaki s/d mata kaki, (6) Tertib.', 'Berdasarkan QS Al-Maidah:6. Niat bersamaan dengan basuhan pertama wajah (dalam hati). Wajah: dari tumbuh rambut hingga dagu, antara dua telinga. ''Sebagian kepala'' = minimal satu helai. Tertib = urutan wajib tidak boleh diacak.', '[{"s":5,"v":6,"label":"Perintah Wudhu"}]', NULL FROM pesantren_bab WHERE kitab_slug = 'safinah' AND bab_order = 2;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 4, 'Pembatal Wudhu (4)', 'نَوَاقِضُ الْوُضُوْءِ', 'نَوَاقِضُ الْوُضُوْءِ أَرْبَعَةٌ: مَا خَرَجَ مِنَ السَّبِيْلَيْنِ، وَزَوَالُ الْعَقْلِ، وَلَمْسُ الْمَرْأَةِ الْأَجْنَبِيَّةِ، وَمَسُّ الذَّكَرِ بِبَطْنِ الْكَفِّ.', 'Pembatal wudhu 4: (1) Keluar sesuatu dari dua jalan, (2) Hilang akal (tidur/pingsan/gila), (3) Menyentuh perempuan ajnabi langsung, (4) Menyentuh kemaluan dengan telapak tangan.', 'Semua yang keluar dari qubul-dubur membatalkan: kentut, kencing, tinja, mani, madzi. Tidur membatalkan kecuali duduk tegak mantap. Menyentuh perempuan ajnabi (kulit-kulit) adalah khas madzhab Syafi''i.', NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'safinah' AND bab_order = 2;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('safinah', 3, 'Shalat', 'بَابُ الصَّلَاةِ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, 'Syarat Wajib & Sah Shalat', 'شُرُوْطُ الصَّلَاةِ', 'شُرُوْطُ الْوُجُوبِ: الْإِسْلَامُ، الْبُلُوغُ، الْعَقْلُ. وَشُرُوْطُ الصِّحَّةِ: الْإِسْلَامُ، التَّمْيِيزُ، الطَّهَارَةُ مِنَ الْحَدَثِ، وَالطَّهَارَةُ مِنَ النَّجَاسَةِ، وَسَتْرُ الْعَوْرَةِ، وَاسْتِقْبَالُ الْقِبْلَةِ، وَدُخُوْلُ الْوَقْتِ.', 'Syarat wajib: Islam, baligh, berakal. Syarat sah: Islam, tamyiz, suci hadats, suci najis, tutup aurat, menghadap kiblat, masuk waktu shalat.', 'Syarat wajib menentukan siapa terkena kewajiban. Syarat sah menentukan bagaimana shalat yang diterima. Anak 7 tahun diperintah shalat meski belum wajib. Aurat laki-laki antara pusar-lutut, perempuan seluruh tubuh kecuali wajah-telapak tangan.', '[{"s":4,"v":103,"label":"Kewajiban Shalat"}]', '["abudawud:495"]' FROM pesantren_bab WHERE kitab_slug = 'safinah' AND bab_order = 3;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 2, 'Rukun Shalat (17)', 'أَرْكَانُ الصَّلَاةِ السَّبْعَةَ عَشَرَ', 'أَرْكَانُ الصَّلَاةِ سَبْعَةَ عَشَرَ: النِّيَّةُ، تَكْبِيرَةُ الْإِحْرَامِ، الْقِيَامُ، قِرَاءَةُ الْفَاتِحَةِ، الرُّكُوعُ، الطُّمَأْنِينَةُ فِيهِ، الِاعْتِدَالُ، الطُّمَأْنِينَةُ فِيهِ، السُّجُودُ مَرَّتَيْنِ، الطُّمَأْنِينَةُ فِيهِ، الْجُلُوسُ بَيْنَ السَّجْدَتَيْنِ، الطُّمَأْنِينَةُ فِيهِ، التَّشَهُّدُ الْأَخِيرُ، الْجُلُوسُ لَهُ، الصَّلَاةُ عَلَى النَّبِيِّ فِيهِ، التَّسْلِيمُ، التَّرْتِيبُ.', '17 Rukun: (1)Niat (2)Takbiratul ihram (3)Berdiri (4)Baca Fatihah (5)Ruku'' (6)Tuma''ninah ruku'' (7)I''tidal (8)Tuma''ninah i''tidal (9)Sujud 2x (10)Tuma''ninah sujud (11)Duduk antara 2 sujud (12)Tuma''ninah duduk (13)Tasyahhud akhir (14)Duduk tasyahhud (15)Shalawat (16)Salam (17)Tertib.', 'Meninggalkan satu rukun membatalkan shalat. Tuma''ninah (diam ±1 detik) adalah rukun paling sering diabaikan. Hadits ''kembalilah dan shalat'' ditujukan untuk orang yang shalat tanpa tuma''ninah — sangat penting!', NULL, '["bukhari:793"]' FROM pesantren_bab WHERE kitab_slug = 'safinah' AND bab_order = 3;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('safinah', 4, 'Zakat & Puasa', 'الزَّكَاةُ وَالصَّوْمُ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, 'Rukun Puasa', 'أَرْكَانُ الصَّوْمِ', 'أَرْكَانُ الصَّوْمِ اثْنَانِ: النِّيَّةُ فِي كُلِّ لَيْلَةٍ، وَالْإِمْسَاكُ عَنِ الْمُفَطِّرَاتِ مِنَ الْفَجْرِ الصَّادِقِ إِلَى غُرُوبِ الشَّمْسِ.', 'Rukun puasa 2: (1) Niat setiap malam sebelum fajar, (2) Menahan dari pembatal puasa sejak fajar shadiq hingga maghrib.', 'Niat puasa Ramadhan wajib tiap malam. Pembatal: makan/minum/jimak sengaja, muntah sengaja, keluarnya mani sengaja, haid/nifas, murtad. Orang sakit dan musafir boleh tidak puasa dan menggantinya.', '[{"s":2,"v":187,"label":"Batas Waktu Puasa"}]', '["abudawud:2454"]' FROM pesantren_bab WHERE kitab_slug = 'safinah' AND bab_order = 4;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 2, 'Zakat Fitrah', 'زَكَاةُ الْفِطْرِ', 'زَكَاةُ الْفِطْرِ وَاجِبَةٌ عَلَى كُلِّ مُسْلِمٍ وَمِقْدَارُهَا صَاعٌ مِنْ قُوْتِ الْبَلَدِ.', 'Zakat fitrah wajib atas setiap Muslim. Besarnya: 1 sha'' (±2,5 kg) dari makanan pokok setempat.', 'Zakat fitrah menyempurnakan puasa dan membersihkan dari perkataan sia-sia selama puasa. Wajib bagi yang memiliki kelebihan dari kebutuhannya pada malam-hari Idul Fitri. Afdhalnya dibayar pada malam/pagi Idul Fitri sebelum shalat Id.', NULL, '["bukhari:1503"]' FROM pesantren_bab WHERE kitab_slug = 'safinah' AND bab_order = 4;

INSERT OR IGNORE INTO pesantren_kitab (slug, category_slug, title_ar, title_id, author, author_death_year, description_id, sort_order) VALUES ('sullamtaufiq', 'fiqih', 'سُلَّمُ التَّوْفِيقِ', 'Sullam Taufiq', 'Syaikh Abdullah Ba''lawi Al-Hadhrami', NULL, 'Kitab fiqih dan akidah komprehensif madzhab Syafi''i', 2);
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('sullamtaufiq', 1, 'Akidah — 20 Sifat Allah', 'الْعَقِيدَةُ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, '20 Sifat Wajib Allah Secara Sistematis', 'الصِّفَاتُ الْعِشْرُونَ', 'يَجِبُ عَلَى كُلِّ مُكَلَّفٍ مَعْرِفَةُ الْعَشَرَةِ الْوَاجِبَةِ وَالْعَشَرَةِ الْمُسْتَحِيلَةِ وَالْجَائِزِ فِي حَقِّ اللهِ. (١) الْوُجُودُ (٢) الْقِدَمُ (٣) الْبَقَاءُ (٤) الْمُخَالَفَةُ لِلْحَوَادِثِ (٥) الْقِيَامُ بِالنَّفْسِ (٦) الْوَحْدَانِيَّةُ (٧) الْقُدْرَةُ (٨) الْإِرَادَةُ (٩) الْعِلْمُ (١٠) الْحَيَاةُ (١١) السَّمْعُ (١٢) الْبَصَرُ (١٣) الْكَلَامُ وَالْمَعْنَوِيَّاتُ السَّبْعُ.', 'Wajib bagi setiap mukallaf mengetahui 20 sifat wajib, 20 sifat mustahil, dan 1 sifat jaiz bagi Allah. (1) Wujud (2) Qidam (3) Baqa'' (4) Mukhalafah (5) Qiyam binafsihi (6) Wahdaniyyah (7) Qudrah (8) Iradah (9) Ilmu (10) Hayah (11) Sama'' (12) Bashar (13) Kalam + 7 Ma''nawiyyah.', 'Sullam Taufiq menambahkan 7 sifat Ma''nawiyyah (turunan dari Ma''ani): Allah bersifat Qadir, Murid, ''Alim, Hayy, Sami'', Bashir, Mutakallim. Ini distinsi ilmu kalam: Ma''ani = sifat yang ada, Ma''nawiyyah = keadaan yang lahir dari Ma''ani.', '[{"s":2,"v":255,"label":"Ayat Kursi"}]', NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 1;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('sullamtaufiq', 2, 'Fiqih — Haji', 'كِتَابُ الْحَجِّ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, 'Rukun Haji (5) & Wajib Haji (6)', 'أَرْكَانُ الْحَجِّ وَوَاجِبَاتُهُ', 'أَرْكَانُ الْحَجِّ خَمْسَةٌ: الْإِحْرَامُ، الْوُقُوفُ بِعَرَفَةَ، طَوَافُ الْإِفَاضَةِ، السَّعْيُ، الْحَلْقُ. وَوَاجِبَاتُهُ سِتَّةٌ: الْإِحْرَامُ مِنَ الْمِيقَاتِ، الْوُقُوفُ إِلَى اللَّيْلِ، الْمَبِيتُ بِمُزْدَلِفَةَ، الْمَبِيتُ بِمِنَى، رَمْيُ الْجِمَارِ، طَوَافُ الْوَدَاعِ.', 'Rukun Haji 5: Ihram, Wukuf di Arafah, Thawaf Ifadhah, Sa''i, Cukur/potong rambut. Wajib Haji 6: Ihram dari miqat, Wukuf hingga malam, Mabit di Muzdalifah, Mabit di Mina, Lempar jumrah, Thawaf Wada''.', 'Meninggalkan rukun = haji batal. Meninggalkan wajib = haji sah tapi wajib bayar dam. Wukuf di Arafah adalah rukun terpenting (al-hajju Arafah). Miqat = batas geografis di mana ihram harus dimulai.', '[{"s":2,"v":196,"label":"Perintah menyempurnakan Haji"}]', '["abudawud:1949"]' FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 2;

INSERT OR IGNORE INTO pesantren_kitab (slug, category_slug, title_ar, title_id, author, author_death_year, description_id, sort_order) VALUES ('fathulqarib', 'fiqih', 'فَتْحُ الْقَرِيبِ الْمُجِيبِ', 'Fathul Qarib', 'Syaikh Ibnu Qasim Al-Ghazi', '918H', 'Syarah Matan Taqrib — fiqih Syafi''i tingkat menengah paling luas digunakan', 3);
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('fathulqarib', 1, 'Nikah & Buyu''', 'النِّكَاحُ وَالْبُيُوعُ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, 'Hukum Nikah & 5 Syarat Sahnya', 'حُكْمُ النِّكَاحِ وَشُرُوطُهُ', 'النِّكَاحُ مُسْتَحَبٌّ لِمَنِ اشْتَاقَ وَلَمْ يَخَفِ الْجَوْرَ، وَوَاجِبٌ لِمَنْ خَافَ الزِّنَا. وَيَصِحُّ بِخَمْسَةِ شُرُوطٍ: مَعْرِفَةُ الزَّوْجَيْنِ، رِضَاهُمَا، وَلِيٌّ، شَاهِدَانِ عَدْلَانِ، صِيغَةٌ.', 'Nikah sunnah bagi yang berhasrat dan tidak khawatir zhalim. Wajib bagi yang khawatir berzina. Sah dengan 5 syarat: (1) Diketahuinya identitas suami-istri, (2) Ridha keduanya, (3) Wali, (4) Dua saksi adil, (5) Shighat ijab kabul.', 'Wali wajib dalam madzhab Syafi''i — nikah tanpa wali tidak sah. Urutan wali: ayah > kakek > saudara laki-laki > paman > wali hakim. Shighat harus menggunakan lafazh ''zawwajtu'' atau ''ankahtuka'' dari wali dan ''qabiltu'' dari mempelai laki-laki.', '[{"s":4,"v":3,"label":"Kebolehan menikah"}]', '["abudawud:2085"]' FROM pesantren_bab WHERE kitab_slug = 'fathulqarib' AND bab_order = 1;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 2, 'Rukun Jual Beli (3) & Syaratnya', 'أَرْكَانُ الْبَيْعِ', 'أَرْكَانُ الْبَيْعِ ثَلَاثَةٌ: عَاقِدٌ، مَعْقُودٌ عَلَيْهِ، صِيغَةٌ. وَيُشْتَرَطُ فِي الْمَعْقُودِ عَلَيْهِ: الطَّهَارَةُ، وَالنَّفْعُ، وَالْقُدْرَةُ عَلَى التَّسْلِيمِ، وَمِلْكُ الْبَائِعِ.', 'Rukun jual beli 3: (1) Aqid (penjual-pembeli), (2) Ma''qud ''alaih (barang), (3) Shighat. Syarat barang: suci, bermanfaat, bisa diserahterimakan, milik penjual.', 'Barang yang tidak boleh dijual: najis (khamr, babi), tidak bisa diserahterimakan, tidak diketahui sifatnya. Unsur yang mengharamkan jual beli: riba (bunga/tambahan), gharar (ketidakjelasan besar), dan maysir (perjudian).', '[{"s":2,"v":275,"label":"Kehalalan jual beli, keharaman riba"}]', NULL FROM pesantren_bab WHERE kitab_slug = 'fathulqarib' AND bab_order = 1;

INSERT OR IGNORE INTO pesantren_kitab (slug, category_slug, title_ar, title_id, author, author_death_year, description_id, sort_order) VALUES ('minhajultalibin', 'fiqih', 'مِنْهَاجُ الطَّالِبِينَ', 'Minhajut Thalibin', 'Imam An-Nawawi', '676H', 'Referensi fiqih Syafi''i paling otoritatif — mu''tamad madzhab seluruh dunia', 4);
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('minhajultalibin', 1, 'Thaharah & Tayammum', 'الطَّهَارَةُ وَالتَّيَمُّمُ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, 'Thaharah, Hadats, dan Tayammum', 'الطَّهَارَةُ وَالتَّيَمُّمُ', 'الطَّهَارَةُ شَرْطٌ لِلصَّلَاةِ وَالطَّوَافِ. وَيَجُوزُ التَّيَمُّمُ عِنْدَ عَدَمِ الْمَاءِ أَوِ الْعَجْزِ عَنِ اسْتِعْمَالِهِ. فَرَائِضُهُ: النِّيَّةُ، وَمَسْحُ الْوَجْهِ، وَمَسْحُ الْيَدَيْنِ إِلَى الْكُوعَيْنِ بِالتُّرَابِ الطَّاهِرِ.', 'Thaharah syarat shalat dan thawaf. Tayammum boleh saat tidak ada air atau tidak mampu menggunakannya. Fardhu tayammum: niat, usap wajah, usap kedua tangan s/d pergelangan dengan tanah suci.', 'Tayammum adalah keringanan Allah yang khas untuk umat Nabi ﷺ. Tanah untuk tayammum harus suci dan mengandung debu. ''Tidak mampu menggunakan air'' mencakup: sakit yang bertambah parah jika terkena air, air hanya untuk minum, atau air sangat mahal.', '[{"s":5,"v":6,"label":"Ayat perintah tayammum"}]', '["bukhari:335"]' FROM pesantren_bab WHERE kitab_slug = 'minhajultalibin' AND bab_order = 1;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('minhajultalibin', 2, 'Siyam & Zakat', 'الصِّيَامُ وَالزَّكَاةُ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, 'Puasa Sunnah Utama', 'الصِّيَامُ الْمَسْنُونُ', 'يُسَنُّ صَوْمُ سِتَّةٍ مِنْ شَوَّالٍ، وَيَوْمِ عَرَفَةَ لِغَيْرِ الْحَاجِّ، وَعَاشُورَاءَ مَعَ تَاسُوعَاءَ، وَالِاثْنَيْنِ وَالْخَمِيسِ، وَثَلَاثَةِ أَيَّامٍ مِنْ كُلِّ شَهْرٍ.', 'Sunnah puasa: 6 hari Syawal, hari Arafah (9 Dzulhijjah) bagi yang tidak haji, Asyura'' (10) + Tasu''a (9 Muharram), Senin-Kamis, 3 hari tiap bulan (ayyam bidh 13-14-15).', 'Puasa 6 Syawal + Ramadhan = pahala puasa setahun. Puasa Arafah = hapus dosa 2 tahun. Puasa Asyura'' = hapus dosa setahun lalu. Senin-Kamis karena Nabi ﷺ suka amal diangkat saat berpuasa.', NULL, '["muslim:1162"]' FROM pesantren_bab WHERE kitab_slug = 'minhajultalibin' AND bab_order = 2;

INSERT OR IGNORE INTO pesantren_kitab (slug, category_slug, title_ar, title_id, author, author_death_year, description_id, sort_order) VALUES ('aqidatulawam', 'akidah', 'عَقِيدَةُ الْعَوَامِّ', 'Aqidatul Awam', 'Syaikh Ahmad Al-Marzuqi Al-Maliki', '1262H', 'Nadhom 57 bait akidah Ahlussunnah — wajib dihafalkan santri', 5);
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('aqidatulawam', 1, '20 Sifat Wajib Allah', 'الصِّفَاتُ الْوَاجِبَةُ للهِ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, 'Bait 1-4: Pembukaan & Sifat Nafsiyyah-Salbiyyah', 'الصِّفَاتُ النَّفْسِيَّةُ وَالسَّلْبِيَّةُ', 'أَبْدَأُ بِاسْمِ اللهِ وَالرَّحْمَنِ *** وَبِالرَّحِيمِ دَائِمِ الْإِحْسَانِ
وَبَعْدُ فَاعْلَمْ وَاجِبَاتِ اللهِ *** عِشْرِينَ وَصْفًا قُلْتُهَا تَنْبِيهَا
وُجُودُهُ قِدَمُهُ وَبَقَاؤُهُ *** وَخَالِفُونَ لِلْحَوَادِثِ جَاؤُهُ
قِيَامُهُ بِنَفْسِهِ فَوَحْدَانِيَّةْ *** وَبَعْدَهَا صِفَاتُهُ الْمَعَانِيَّةْ', 'Aku mulai dengan nama Allah, Ar-Rahman, Ar-Rahim. Ketahuilah sifat wajib Allah ada 20. (Sifat-sifatnya:) Ada (Wujud), Terdahulu (Qidam), Kekal (Baqa''), Berbeda dari makhluk (Mukhalafah), Berdiri Sendiri (Qiyam binafsihi), Esa (Wahdaniyyah). Setelah itu sifat-sifat Ma''ani.', '6 sifat pertama: Nafsiyyah (1: Wujud) dan Salbiyyah (5: Qidam, Baqa'', Mukhalafah, Qiyam binafsihi, Wahdaniyyah). Salbiyyah menafikan yang tidak layak bagi Allah: tidak ada, baru, fana, menyerupai makhluk, bergantung, berbilang. Wajib atas setiap mukallaf meyakini ini.', '[{"s":112,"v":1,"label":"Surah Al-Ikhlas — Tauhid"}]', NULL FROM pesantren_bab WHERE kitab_slug = 'aqidatulawam' AND bab_order = 1;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 2, 'Bait 5-8: Sifat Ma''ani (7 Sifat)', 'الصِّفَاتُ الْمَعَانِيَّةُ السَّبْعُ', 'قُدْرَةٌ إِرَادَةٌ عِلْمٌ حَيَاةُ *** سَمْعٌ وَبَصَرٌ ثُمَّ كَلَامُ الذَّاتِ
وَيَسْتَحِيلُ عَلَى الْإِلَهِ ضِدُّهَا *** وَيَجُوزُ أَنْ يَفْعَلَ مَا يُرِيدُهَا', 'Tujuh sifat Ma''ani: Qudrah, Iradah, Ilmu, Hayah, Sama'', Bashar, Kalam. Mustahil bagi Allah lawannya. Dan jaiz bagi Allah melakukan apa yang Dia kehendaki.', 'Qudrah=kuasa mutlak. Iradah=kehendak mutlak. Ilmu=mengetahui segala sesuatu. Hayah=hidup kekal. Sama''=mendengar tanpa alat. Bashar=melihat tanpa alat. Kalam=firman qadim bukan makhluk. Lawan setiap sifat ini adalah mustahil bagi Allah.', '[{"s":2,"v":255,"label":"Ayat Kursi — sifat Allah"}]', NULL FROM pesantren_bab WHERE kitab_slug = 'aqidatulawam' AND bab_order = 1;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('aqidatulawam', 2, 'Sifat Wajib Para Rasul', 'صِفَاتُ الرُّسُلِ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, '4 Sifat Wajib, 4 Mustahil, 1 Jaiz bagi Rasul', 'وَاجِبَاتُ الرُّسُلِ', 'وَيَجِبُ لِلرُّسُلِ الْكِرَامِ أَرْبَعُ *** صِدْقٌ أَمَانَةٌ وَالْبَلَاغُ وَالْفِطَنُ
وَيُسْتَحِيلُ ضِدُّهَا: الْكَذِبُ وَالْخَوْنَةُ وَالْكِتْمَانُ وَالْبَلَادَةُ
وَيَجُوزُ فِيهِمُ الْأَعْرَاضُ الْبَشَرِيَّةُ', 'Wajib bagi para rasul: Shidq (jujur), Amanah, Tabligh (menyampaikan), Fathanah (cerdas). Mustahil: dusta, khianat, menyembunyikan wahyu, bodoh. Jaiz: hal-hal basyariah yang tidak mengurangi kerasulan.', '4 sifat wajib rasul adalah jaminan kebenaran risalah. Shidq: tidak pernah bohong. Amanah: tidak pernah khianat. Tabligh: semua wahyu disampaikan, tidak ada yang disembunyikan. Fathanah: kecerdasan luar biasa untuk membela dan menyampaikan risalah.', '[{"s":53,"v":3,"label":"Nabi tidak bicara dari hawa nafsu"}]', NULL FROM pesantren_bab WHERE kitab_slug = 'aqidatulawam' AND bab_order = 2;

INSERT OR IGNORE INTO pesantren_kitab (slug, category_slug, title_ar, title_id, author, author_death_year, description_id, sort_order) VALUES ('ummulmabrahim', 'akidah', 'أُمُّ الْبَرَاهِينِ', 'Umm al-Barahin (As-Sanusiyyah)', 'Imam Muhammad bin Yusuf As-Sanusi', '895H', 'Risalah akidah Asy''ariyyah yang paling ringkas dan padat — wajib hafal santri', 6);
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('ummulmabrahim', 1, 'Sifat Allah 20 — Ringkas', 'الصِّفَاتُ الْعِشْرُونَ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, 'Pembukaan & Sifat Nafsiyyah', 'الصِّفَةُ النَّفْسِيَّةُ', 'اِعْلَمْ أَنَّهُ يَجِبُ فِي حَقِّ اللهِ تَعَالَى الْوُجُودُ وَيَسْتَحِيلُ الْعَدَمُ وَيَجُوزُ أَنْ يَفْعَلَ كُلَّ مُمْكِنٍ أَوْ يَتْرُكَهُ.', 'Ketahuilah bahwa wajib bagi Allah sifat Wujud (Ada), mustahil bagi-Nya ''Adam (tidak ada), dan jaiz bagi-Nya melakukan atau tidak melakukan segala yang mungkin.', 'As-Sanusiyyah (Umm al-Barahin) adalah risalah paling ringkas dan padat tentang akidah Asy''ariyyah. Sangat populer di pesantren-pesantren tradisional sebagai kitab hafalan pertama dalam akidah. Pengarangnya, Imam As-Sanusi (Tlemcen, Aljazair), adalah salah satu teolog terbesar madzhab Asy''ariyyah.', '[{"s":2,"v":255,"label":"Ayat Kursi — Wujud Allah"}]', NULL FROM pesantren_bab WHERE kitab_slug = 'ummulmabrahim' AND bab_order = 1;

INSERT OR IGNORE INTO pesantren_kitab (slug, category_slug, title_ar, title_id, author, author_death_year, description_id, sort_order) VALUES ('tijandaruri', 'akidah', 'تِيجَانُ الدُّرَارِيِّ', 'Tijan Daruri', 'Syaikh Nawawi Al-Bantani— Ulama Nusantara', '1316H', 'Syarah akidah karya ulama Nusantara terbesar — Imam Nawawi Al-Bantani Al-Jawi', 7);
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('tijandaruri', 1, 'Iman & Tauhid', 'الْإِيمَانُ وَالتَّوْحِيدُ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, 'Definisi Iman & Tiga Pembagian Tauhid', 'الْإِيمَانُ وَأَقْسَامُ التَّوْحِيدِ', 'الْإِيمَانُ شَرْعًا: التَّصْدِيقُ بِالْقَلْبِ وَالْإِقْرَارُ بِاللِّسَانِ. وَالتَّوْحِيدُ ثَلَاثَةٌ: تَوْحِيدُ الذَّاتِ — اللهُ وَاحِدٌ فِي ذَاتِهِ. وَتَوْحِيدُ الصِّفَاتِ — صِفَاتُهُ لَا تُشْبِهُ صِفَاتِ الْمَخْلُوقِينَ. وَتَوْحِيدُ الْأَفْعَالِ — هُوَ الْخَالِقُ الْمُدَبِّرُ وَحْدَهُ.', 'Iman syar''i: membenarkan dengan hati dan mengikrarkan dengan lisan. Tauhid ada 3: (1) Tauhid Dzat — Allah Esa dalam Dzat, tiada sekutu; (2) Tauhid Sifat — sifat-Nya tidak menyerupai makhluk; (3) Tauhid Af''al — Allah satu-satunya Pencipta dan Pengatur.', 'Syaikh Nawawi Al-Bantani (Banten, Jawa — wafat di Mekah 1316H) adalah ulama Nusantara paling produktif. Kitab-kitabnya menjadi rujukan pesantren di seluruh dunia Melayu dan Timur Tengah. Tiga pembagian tauhid ini merangkum seluruh keyakinan tentang Allah.', '[{"s":112,"v":1,"label":"Al-Ikhlas — Tauhid Dzat"}]', '["bukhari:52"]' FROM pesantren_bab WHERE kitab_slug = 'tijandaruri' AND bab_order = 1;

INSERT OR IGNORE INTO pesantren_kitab (slug, category_slug, title_ar, title_id, author, author_death_year, description_id, sort_order) VALUES ('talimutaliam', 'akhlak', 'تَعْلِيْمُ الْمُتَعَلِّمِ', 'Ta''lim Muta''allim', 'Syaikh Burhanuddin Az-Zarnuji', NULL, 'Kitab adab menuntut ilmu — wajib dibaca setiap santri sebelum belajar', 8);
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('talimutaliam', 1, 'Keutamaan Ilmu', 'فَضِيْلَةُ الْعِلْمِ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, 'Wajibnya Menuntut Ilmu', 'وُجُوبُ طَلَبِ الْعِلْمِ', 'اِعْلَمْ أَنَّهُ يَجِبُ عَلَى كُلِّ مُسْلِمٍ وَمُسْلِمَةٍ تَعَلُّمُ الْعِلْمِ. وَإِنَّمَا يَجِبُ تَعَلُّمُ عِلْمِ الْحَالِ — وَهُوَ مَا يَحْتَاجُ إِلَيْهِ.', 'Menuntut ilmu wajib bagi setiap Muslim laki-laki dan perempuan. Yang wajib adalah ilmul hal — ilmu yang diperlukan untuk menjalankan keadaannya saat ini.', 'Ilmu fardhu ''ain: akidah yang benar, fiqih ibadah (shalat, puasa, zakat, haji), dan ilmu akhlak. Fardhu kifayah: ilmu yang jika sudah ada yang mempelajarinya di suatu komunitas, kewajiban gugur dari lainnya (kedokteran, teknik, dll).', '[{"s":58,"v":11,"label":"Allah angkat derajat orang berilmu"}]', '["ibnmajah:224"]' FROM pesantren_bab WHERE kitab_slug = 'talimutaliam' AND bab_order = 1;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 2, 'Ilmu tanpa Amal bagaikan Pohon tanpa Buah', 'الْعِلْمُ بِلَا عَمَلٍ', 'قِيْلَ: الْعِلْمُ بِلَا عَمَلٍ كَالشَّجَرِ بِلَا ثَمَرٍ. وَأَفْضَلُ الْعِلْمِ عِلْمُ الْحَالِ وَأَفْضَلُ الْأَعْمَالِ حِفْظُ الْحَالِ.', 'Dikatakan: ilmu tanpa amal bagaikan pohon tanpa buah. Ilmu terbaik adalah ilmu yang relevan dengan keadaan, dan amal terbaik adalah menjaga pengamalannya.', 'Ilmu yang tidak diamalkan menjadi hujjah yang memberatkan di akhirat. Para ulama salaf sangat takut dengan ilmu yang tidak diamalkan. Imam Ahmad berkata: ilmu menuntut amal — jika tidak diamalkan, ilmu itu pergi.', NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'talimutaliam' AND bab_order = 1;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('talimutaliam', 2, 'Niat & Memilih Guru', 'النِّيَّةُ وَاخْتِيَارُ الْأُسْتَاذِ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, 'Meluruskan Niat dalam Belajar', 'تَصْحِيحُ النِّيَّةِ', 'يَنْبَغِي لِطَالِبِ الْعِلْمِ أَنْ يَنْوِيَ بِطَلَبِ الْعِلْمِ رِضَا اللهِ وَالدَّارَ الْآخِرَةَ وَإِزَالَةَ الْجَهْلِ عَنْ نَفْسِهِ وَعَنِ الْجُهَّالِ وَإِحْيَاءَ الدِّيْنِ وَإِبْقَاءَ الْإِسْلَامِ.', 'Penuntut ilmu hendaknya berniat: demi ridha Allah, demi akhirat, untuk menghilangkan kebodohan dari diri dan orang lain, untuk menghidupkan agama, dan untuk melestarikan Islam.', 'Niat ikhlas adalah penentu diterimanya amal. Menuntut ilmu dengan niat riya'' atau kebanggaan duniawi adalah tercela. Niat yang benar menjadikan tidur dan makan penuntut ilmu pun menjadi ibadah karena menunjang aktivitas belajarnya.', NULL, '["bukhari:1"]' FROM pesantren_bab WHERE kitab_slug = 'talimutaliam' AND bab_order = 2;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 2, 'Memuliakan Ilmu & Guru', 'تَعْظِيمُ الْعِلْمِ وَالْأُسْتَاذِ', 'لَا يَنَالُ الطَّالِبُ الْعِلْمَ وَلَا يَنْتَفِعُ بِهِ إِلَّا بِتَعْظِيمِ الْعِلْمِ وَأَهْلِهِ وَتَعْظِيمِ الْأُسْتَاذِ. قَالَ عَلِيٌّ: أَنَا عَبْدُ مَنْ عَلَّمَنِي حَرْفًا وَاحِدًا.', 'Penuntut ilmu tidak berhasil kecuali dengan memuliakan ilmu, ulama, dan gurunya. Ali bin Abi Thalib رضي الله عنه berkata: ''Aku adalah hamba siapapun yang mengajariku satu huruf.''', 'Memuliakan guru bukan feodalisme — ia adalah kunci keberkahan ilmu secara spiritual. Az-Zarnuji menceritakan banyak ulama yang kehilangan barakah ilmunya karena kurang adab kepada guru. Imam Syafi''i membalikkan halaman kitab perlahan agar tidak mengganggu Imam Malik.', NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'talimutaliam' AND bab_order = 2;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('talimutaliam', 3, 'Wara'' & Ketekunan', 'الْوَرَعُ وَالْمُثَابَرَةُ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, 'Wara'' dan Ilmu bagaikan Cahaya', 'الْوَرَعُ وَنُورُ الْعِلْمِ', 'يَنْبَغِي لِطَالِبِ الْعِلْمِ أَنْ يَتَوَرَّعَ. قَالَ الْإِمَامُ الشَّافِعِيُّ: شَكَوْتُ إِلَى وَكِيعٍ سُوءَ حِفْظِي — فَأَرْشَدَنِي إِلَى تَرْكِ الْمَعَاصِي — وَأَخْبَرَنِي بِأَنَّ الْعِلْمَ نُورٌ — وَنُورُ اللهِ لَا يُهْدَى لِعَاصِي.', 'Penuntut ilmu hendaknya bersifat wara''. Imam Syafi''i berkata: ''Aku mengadu kepada Waki'' tentang buruknya hafalanku — ia membimbingku meninggalkan maksiat — ia memberitahu bahwa ilmu adalah cahaya — dan cahaya Allah tidak diberikan kepada orang yang bermaksiat.''', 'Hubungan kesucian jiwa dan ketajaman hafalan terbukti empiris oleh para ulama. Imam Syafi''i memiliki hafalan luar biasa karena sangat menjaga diri dari dosa kecil sekalipun. Ilmu adalah amanah yang hanya dipercayakan kepada hati yang bersih.', NULL, '["muslim:1015"]' FROM pesantren_bab WHERE kitab_slug = 'talimutaliam' AND bab_order = 3;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 2, 'Tiga Macam Cobaan bagi yang Tidak Wara''', 'عُقُوْبَةُ تَرْكِ الْوَرَعِ', 'رُوِيَ فِي هٰذَا الْبَابِ حَدِيثًا عَنْ رَسُولِ اللهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ: مَنْ لَمْ يَتَوَرَّعْ فِي طَلَبِ الْعِلْمِ ابْتَلَاهُ اللهُ تَعَالَى بِإِحْدَى ثَلَاثٍ: إِمَّا أَنْ يُمِيتَهُ فِي شَبَابِهِ، أَوْ يُوقِعَهُ فِي الْقُرَى، أَوْ يَبْتَلِيَهُ بِخِدْمَةِ السُّلْطَانِ.', 'Diriwayatkan dalam bab ini sebuah hadits dari Rasulullah ﷺ bahwa beliau bersabda: barangsiapa tidak menjaga diri dengan wara'' dalam menuntut ilmu, Allah akan mengujinya dengan salah satu dari tiga hal: kematian di usia muda, terdampar di pelosok yang sepi dari ilmu, atau terjerumus melayani penguasa yang menjauhkannya dari ilmu.', 'Az-Zarnuji meletakkan ancaman ini sebagai peringatan keras: ilmu yang dicari tanpa dibarengi wara'' (menjaga diri dari yang haram dan syubhat) berisiko tidak memberi manfaat — bahkan bisa berbalik menjadi musibah bagi pemiliknya. ''Terjerumus melayani penguasa'' di sini dipahami sebagai gambaran terjebak dalam urusan dunia yang menjauhkan dari ilmu dan keikhlasan.', NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'talimutaliam' AND bab_order = 3;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('talimutaliam', 4, 'Cara Memilih Ilmu, Guru & Teman', 'اخْتِيَارُ الْعِلْمِ وَالْأُسْتَاذِ وَالرَّفِيْقِ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, 'Mendahulukan Ilmu yang Paling Dibutuhkan', 'تَقْدِيمُ مَا يُحْتَاجُ إِلَيْهِ', 'يَنْبَغِي لِطَالِبِ الْعِلْمِ أَنْ يَخْتَارَ مِنْ كُلِّ عِلْمٍ أَحْسَنَهُ، وَمَا يَحْتَاجُ إِلَيْهِ فِي أَمْرِ دِينِهِ، ثُمَّ مَا يَحْتَاجُ إِلَيْهِ فِي الْحَالِ، ثُمَّ مَا يَحْتَاجُ إِلَيْهِ فِي الْمَآلِ.', 'Penuntut ilmu hendaknya memilih dari setiap bidang ilmu bagian yang terbaik, dan yang paling ia butuhkan untuk urusan agamanya — kemudian apa yang ia butuhkan untuk keadaannya saat ini, lalu apa yang ia butuhkan untuk masa depannya.', 'Prinsip ini mengajarkan prioritas dalam belajar: agama dulu, kebutuhan mendesak hari ini, baru kemudian bekal untuk masa depan. Bukan berarti ilmu dunia tidak penting, tetapi urutan ini menjaga agar penuntut ilmu tidak tersesat mengejar ilmu yang belum waktunya sementara ilmu yang lebih mendasar terbengkalai.', NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'talimutaliam' AND bab_order = 4;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 2, 'Memilih Guru yang Paling Berilmu, Wara'', dan Senior', 'اخْتِيَارُ الْأُسْتَاذِ الْأَعْلَمِ وَالْأَوْرَعِ', 'وَأَمَّا اخْتِيَارُ الْأُسْتَاذِ فَيَنْبَغِي أَنْ يَخْتَارَ الْأَعْلَمَ وَالْأَوْرَعَ وَالْأَسَنَّ، كَمَا اخْتَارَ أَبُو حَنِيفَةَ رَحِمَهُ اللهُ تَعَالَى حِينَ شَاوَرَهُ حَمَّادَ بْنَ أَبِي سُلَيْمَانَ بَعْدَ التَّأَمُّلِ وَالتَّفَكُّرِ.', 'Adapun dalam memilih guru, hendaknya seseorang memilih yang paling berilmu, paling wara'', dan paling tua (paling senior dan berpengalaman) — sebagaimana Imam Abu Hanifah rahimahullah memilih (gurunya) setelah bermusyawarah, merenung, dan berpikir matang, sehingga akhirnya memilih Hammad bin Abi Sulaiman.', 'Az-Zarnuji menjadikan kisah Imam Abu Hanifah sebagai teladan: memilih guru bukan keputusan instan, melainkan hasil pertimbangan matang. Tiga kriteria — keilmuan, kewaraan (kesalehan), dan kematangan/usia — saling melengkapi: ilmu tanpa wara'' berisiko menyesatkan, sementara wara'' tanpa ilmu yang memadai juga membuat bimbingan kurang mumpuni.', NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'talimutaliam' AND bab_order = 4;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('talimutaliam', 5, 'Kesungguhan, Istiqamah & Cita-cita', 'الْجِدُّ وَالْمُوَاظَبَةُ وَعُلُوُّ الْهِمَّةِ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, 'Kesungguhan adalah Pintu Keberhasilan', 'الْجِدُّ بَابُ النَّجَاحِ', 'ثُمَّ لَا بُدَّ لِطَالِبِ الْعِلْمِ مِنَ الْجِدِّ وَالْمُواظَبَةِ وَالْمُلَازَمَةِ، وَإِلَيْهِ الْإِشَارَةُ فِي قَوْلِهِ تَعَالَى: وَالَّذِينَ جَاهَدُوا فِينَا لَنَهْدِيَنَّهُمْ سُبُلَنَا.', 'Penuntut ilmu tidak akan berhasil tanpa kesungguhan, ketekunan, dan konsistensi (terus-menerus tidak putus). Hal ini diisyaratkan dalam firman Allah Ta''ala: ''Dan orang-orang yang bersungguh-sungguh (berjihad) untuk (mencari keridhaan) Kami, niscaya akan Kami tunjukkan kepada mereka jalan-jalan Kami.''', 'Az-Zarnuji menafsirkan ayat tentang ''jihad fi sabilillah'' (QS Al-Ankabut: 69) secara lebih luas: kesungguhan dalam menuntut ilmu termasuk bentuk perjuangan di jalan Allah, dan balasannya adalah petunjuk serta kemudahan jalan dari Allah sendiri. Ini menegaskan bahwa hasil belajar bukan sekadar produk usaha manusia, tetapi juga anugerah hidayah dari Allah bagi yang sungguh-sungguh.', '[{"s":29,"v":69,"label":"Allah menunjukkan jalan bagi yang bersungguh-sungguh"}]', NULL FROM pesantren_bab WHERE kitab_slug = 'talimutaliam' AND bab_order = 5;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('talimutaliam', 6, 'Kasih Sayang, Nasihat & Tawakal', 'الشَّفَقَةُ وَالنَّصِيْحَةُ وَالتَّوَكُّلُ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, 'Pemilik Ilmu Harus Penyayang, Bukan Pendengki', 'صَاحِبُ الْعِلْمِ يَكُونُ مُشْفِقًا', 'يَنْبَغِي أَنْ يَكُونَ صَاحِبُ الْعِلْمِ مُشْفِقًا نَاصِحًا، وَلَا يَكُونَ حَاسِدًا، فَإِنَّ الْحَسَدَ يَضُرُّ وَلَا يَنْفَعُ.', 'Hendaknya seorang yang berilmu bersikap penyayang dan suka memberi nasihat (kepada sesama penuntut ilmu), serta tidak menjadi orang yang dengki — karena sifat dengki itu hanya merugikan dan tidak mendatangkan manfaat apa pun.', 'Bagian ini menempatkan akhlak sosial sebagai bagian dari adab keilmuan: ilmu yang baik melahirkan kepedulian kepada sesama pencari ilmu, bukan rasa iri ketika orang lain lebih unggul. Dengki terhadap sesama pelajar justru menggerogoti keberkahan ilmu yang dimiliki sendiri.', NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'talimutaliam' AND bab_order = 6;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 2, 'Tawakal: Tidak Disibukkan Urusan Rezeki saat Belajar', 'التَّوَكُّلُ وَعَدَمُ الاِنْشِغَالِ بِالرِّزْقِ', 'ثُمَّ لَا بُدَّ لِطَالِبِ الْعِلْمِ مِنَ التَّوَكُّلِ فِي طَلَبِ الْعِلْمِ، وَلَا يَشْتَغِلْ قَلْبُهُ بِأَمْرِ الرِّزْقِ وَلَا يُهْتَمَّ لِذٰلِكَ.', 'Penuntut ilmu hendaknya bertawakal kepada Allah dalam mencari ilmu, dan jangan sampai hatinya disibukkan oleh urusan rezeki ataupun menjadikannya sebagai kekhawatiran (yang berlebihan).', 'Tawakal di sini bukan berarti meninggalkan usaha, melainkan tidak membiarkan pikiran tentang rezeki menyita fokus dan ketenangan hati saat menimba ilmu. Az-Zarnuji mengajarkan bahwa kekhawatiran berlebihan terhadap dunia justru menjadi penghalang konsentrasi dan keberkahan dalam belajar.', NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'talimutaliam' AND bab_order = 6;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('talimutaliam', 7, 'Hal-hal Penguat & Pelemah Hafalan', 'مَا يُقَوِّي الْحِفْظَ وَمَا يُضْعِفُهُ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, 'Sebab-sebab Kuatnya Hafalan', 'أَسْبَابُ قُوَّةِ الْحِفْظِ', 'أَقْوَى أَسْبَابِ الْحِفْظِ: الْجِدُّ، وَالْمُوَاظَبَةُ، وَتَقْلِيلُ الْغِذَاءِ، وَصَلَاةُ اللَّيْلِ، وَقِرَاءَةُ الْقُرْآنِ، فَإِنَّ قِرَاءَةَ الْقُرْآنِ نَظَرًا مِنْ أَسْبَابِ الْحِفْظِ.', 'Sebab-sebab paling kuat untuk menguatkan hafalan adalah: kesungguhan, ketekunan, mengurangi makan (tidak berlebihan), shalat malam, dan membaca Al-Qur''an — karena membaca Al-Qur''an dengan melihat (mushaf) termasuk salah satu sebab kuatnya hafalan.', 'Lima hal ini menunjukkan bahwa kekuatan hafalan tidak semata soal teknik menghafal, tetapi juga terkait kondisi fisik dan spiritual: pola makan yang terkendali menjaga kejernihan pikiran, shalat malam dan membaca Al-Qur''an menanamkan keberkahan dan ketenangan batin yang menjadi wadah bagi ilmu untuk meresap dan bertahan dalam memori.', NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'talimutaliam' AND bab_order = 7;

INSERT OR IGNORE INTO pesantren_kitab (slug, category_slug, title_ar, title_id, author, author_death_year, description_id, sort_order) VALUES ('bidayatulhidayah', 'akhlak', 'بِدَايَةُ الْهِدَايَةِ', 'Bidayatul Hidayah', 'Imam Al-Ghazali', '505H', 'Panduan awal suluk dan adab harian Muslim — karya Hujjatul Islam', 9);
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('bidayatulhidayah', 1, 'Adab Harian', 'الْآدَابُ الْيَوْمِيَّةُ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, 'Adab Bangun Tidur hingga Keluar Rumah', 'آدَابُ الِاسْتِيقَاظِ', 'إِذَا اسْتَيْقَظْتَ مِنَ النَّوْمِ فَاعْلَمْ أَنَّ اللهَ رَدَّ إِلَيْكَ رُوحَكَ. فَاحْمَدْهُ وَقُلِ: الْحَمْدُ لِلَّهِ الَّذِي أَحْيَانَا بَعْدَ مَا أَمَاتَنَا وَإِلَيْهِ النُّشُورُ. ثُمَّ تَذَكَّرِ اللهَ قَبْلَ أَنْ تَفْتَحَ عَيْنَيْكَ.', 'Saat bangun tidur, ketahuilah Allah telah mengembalikan ruhmu. Bersyukurlah dan baca: ''Alhamdulillahilladzi ahyana ba''da ma amatana wa ilaihin nushur.'' Ingatlah Allah sebelum membuka mata.', 'Al-Ghazali menspiritualkan rutinitas harian. Tidur = kematian kecil (QS Az-Zumar:42). Bangun = nikmat hidup yang dikembalikan. Mengingat Allah sebelum membuka mata = melatih hati selalu bersama Allah. Ini adalah latihan ihsan: beribadah seolah melihat Allah.', '[{"s":39,"v":42,"label":"Allah menahan ruh saat tidur"}]', '["bukhari:6312"]' FROM pesantren_bab WHERE kitab_slug = 'bidayatulhidayah' AND bab_order = 1;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('bidayatulhidayah', 2, 'Menjaga Anggota Tubuh', 'حِفْظُ الْجَوَارِحِ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, 'Menjaga 7 Anggota Tubuh dari Maksiat', 'حِفْظُ الْجَوَارِحِ السَّبْعَةِ', 'وَاحْفَظِ الْأَعْضَاءَ السَّبْعَةَ مِنَ الْمَعَاصِي: الْعَيْنَيْنِ — لَا تَنْظُرْ إِلَى مَحَارِمِ اللهِ. وَالْأُذُنَيْنِ — لَا تَسْمَعِ الْغِيبَةَ. وَاللِّسَانَ — لَا تَكْذِبْ وَلَا تَغْتَبْ. وَالْيَدَيْنِ — لَا تَأْخُذْ حَرَامًا. وَالرِّجْلَيْنِ — لَا تَمْشِ إِلَى مَعْصِيَةٍ. وَالْبَطْنَ — لَا تَأْكُلْ حَرَامًا. وَالْفَرْجَ — لَا تَزْنِ.', 'Jaga 7 anggota tubuh dari maksiat: Mata — jangan memandang yang haram. Telinga — jangan mendengar ghibah. Lisan — jangan berdusta dan berghibah. Tangan — jangan ambil yang haram. Kaki — jangan melangkah ke maksiat. Perut — jangan makan yang haram. Kemaluan — jangan berzina.', 'Al-Ghazali menjadikan 7 anggota tubuh sebagai gate keeper akhlak Islam. Setiap anggota memiliki potensi dosa dan potensi ibadah. Menjaga lisan adalah yang paling berat — hadits menyebut lisan sebagai sumber paling banyak mendatangkan azab. Menjaga perut dari haram adalah kunci terbukanya ibadah yang diterima.', NULL, '["bukhari:6018"]' FROM pesantren_bab WHERE kitab_slug = 'bidayatulhidayah' AND bab_order = 2;

INSERT OR IGNORE INTO pesantren_kitab (slug, category_slug, title_ar, title_id, author, author_death_year, description_id, sort_order) VALUES ('nashaihuddiniyyah', 'akhlak', 'النَّصَائِحُ الدِّينِيَّةُ', 'Nashaihud Diniyyah', 'Al-Habib Abdullah Al-Haddad', '1132H', 'Nasihat-nasihat agama dari Al-Imam Al-Haddad Ba''alawi Hadhramaut', 10);
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('nashaihuddiniyyah', 1, 'Taqwa & Tawakal', 'التَّقْوَى وَالتَّوَكُّلُ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, 'Wasiat Taqwa & Hakikatnya', 'الْوَصِيَّةُ بِالتَّقْوَى', 'أُوصِيكُمْ وَنَفْسِي بِتَقْوَى اللهِ. وَحَقِيقَةُ التَّقْوَى: أَنْ لَا يَرَاكَ اللهُ حَيْثُ نَهَاكَ وَلَا يَفْتَقِدَكَ حَيْثُ أَمَرَكَ. وَفِيهَا سَعَادَةُ الدَّارَيْنِ وَنَجَاةٌ مِنْ كُلِّ مَكْرُوهٍ.', 'Aku berwasiat taqwa kepada kalian dan diriku. Hakikat taqwa: Allah tidak melihatmu di tempat yang Ia larang, dan Allah tidak kehilanganmu di tempat yang Ia perintahkan. Di dalamnya terdapat kebahagiaan dunia-akhirat dan keselamatan dari segala yang dibenci.', 'Al-Imam Al-Haddad (Tarim, Hadhramaut, keturunan Nabi ﷺ) adalah imam besar thariqah Ba''alawiyyah abad 17-18M. Definisi taqwa ini adalah yang paling indah dan populer di kalangan ulama: di mana ada larangan Allah — engkau tidak ada di sana; di mana ada perintah Allah — engkau selalu hadir.', '[{"s":64,"v":16,"label":"Perintah taqwa semampu kalian"}]', '["tirmidzi:1987"]' FROM pesantren_bab WHERE kitab_slug = 'nashaihuddiniyyah' AND bab_order = 1;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 2, 'Tawakal kepada Allah', 'التَّوَكُّلُ عَلَى اللهِ', 'التَّوَكُّلُ: صِدْقُ اعْتِمَادِ الْقَلْبِ عَلَى اللهِ فِي اسْتِجْلَابِ الْمَصَالِحِ وَدَفْعِ الْمَضَارِّ مَعَ الْأَخْذِ بِالْأَسْبَابِ.', 'Tawakal adalah sungguh-sungguhnya bersandar hati kepada Allah dalam mencari kemanfaatan dan menolak mudarat — disertai mengambil sebab-sebab (ikhtiar/usaha).', 'Tawakal yang benar bukan pasif tanpa usaha. Usaha semaksimal kemampuan, lalu serahkan hasilnya kepada Allah. Hadits burung: pergi pagi lapar + pulang kenyang = tawakal disertai bergerak mencari rezeki. Meninggalkan sebab = sombong kepada Allah.', NULL, '["tirmidzi:2344"]' FROM pesantren_bab WHERE kitab_slug = 'nashaihuddiniyyah' AND bab_order = 1;

INSERT OR IGNORE INTO pesantren_kitab (slug, category_slug, title_ar, title_id, author, author_death_year, description_id, sort_order) VALUES ('jurumiyah', 'nahwu-shorof', 'مُقَدِّمَةُ الْآجُرُّومِيَّةِ', 'Al-Jurumiyyah', 'Ibnu Ajurrum Ash-Shanhaji', '723H', 'Kitab nahwu paling dasar dan masyhur di dunia Islam', 11);
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('jurumiyah', 1, 'Kalam & Pembagiannya', 'بَابُ الْكَلَامِ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, 'Definisi Kalam', 'تَعْرِيفُ الْكَلَامِ', 'الْكَلَامُ هُوَ اللَّفْظُ الْمُرَكَّبُ الْمُفِيدُ بِالْوَضْعِ. وَأَقْسَامُهُ ثَلَاثَةٌ: اِسْمٌ، وَفِعْلٌ، وَحَرْفٌ جَاءَ لِمَعْنًى.', 'Kalam adalah lafazh yang tersusun, mengandung faedah (makna sempurna), berdasarkan konvensi bahasa Arab. Pembagiannya tiga: Isim, Fi''il, dan Harf.', '4 unsur kalam: (1) Lafzh=ucapan; (2) Murakkab=tersusun min.2 unsur; (3) Mufid=bermakna sempurna; (4) Bil-wadh''=konvensi Arab. Contoh: جَاءَ زَيْدٌ (kalam). Bukan kalam: إِنْ قَامَ (belum sempurna). Tiga jenis kata adalah fondasi seluruh ilmu nahwu.', NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'jurumiyah' AND bab_order = 1;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 2, 'Tanda-tanda Isim, Fi''il & Harf', 'عَلَامَاتُ الِاسْمِ وَالْفِعْلِ وَالْحَرْفِ', 'فَالِاسْمُ يُعْرَفُ بِالْخَفْضِ وَالتَّنْوِينِ وَدُخُولِ الْأَلِفِ وَاللَّامِ. وَالْفِعْلُ يُعْرَفُ بِقَدْ وَالسِّينِ وَسَوْفَ وَتَاءِ التَّأْنِيثِ السَّاكِنَةِ. وَالْحَرْفُ مَا لَا يَصْلُحُ مَعَهُ دَلِيلُ الِاسْمِ وَلَا الْفِعْلِ.', 'Isim: bisa dikasrahkan, ditanwin, dimasuki ال. Fi''il: bisa dimasuki قَدْ، سَ، سَوْفَ، تْ di akhir. Harf: tidak bisa menerima tanda isim maupun fi''il.', 'Tanwin (ٌ ً ٍ) = pasti isim. Alif-lam (الـ) = pasti isim. Huruf jar (مِنْ، إِلَى) hanya masuk pada isim. Qad+madhi=tahqiq (قَدْ قَامَ). Sin/saufa+mudhari''=akan (سَيَقُوْمُ). Harf seperti مِنْ tidak bisa menerima semua tanda itu.', NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'jurumiyah' AND bab_order = 1;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('jurumiyah', 2, 'I''rab', 'بَابُ الْإِعْرَابِ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, 'Definisi & Pembagian I''rab', 'تَعْرِيفُ الْإِعْرَابِ وَأَقْسَامُهُ', 'الْإِعْرَابُ هُوَ تَغْيِيرُ أَوَاخِرِ الْكَلِمِ لِاخْتِلَافِ الْعَوَامِلِ. أَقْسَامُهُ: رَفْعٌ وَنَصْبٌ وَخَفْضٌ وَجَزْمٌ. لِلْأَسْمَاءِ: رَفْعٌ، نَصْبٌ، خَفْضٌ. لِلْأَفْعَالِ: رَفْعٌ، نَصْبٌ، جَزْمٌ.', 'I''rab = perubahan harakat akhir kata karena amil. 4 macam: Rafa'' (ـُ), Nashab (ـَ), Jar/Khafadh (ـِ), Jazm (ـْ). Isim: rafa''-nashab-jar. Fi''il: rafa''-nashab-jazm.', 'Contoh: كِتَابٌ (rafa''/subjek جَاءَ كِتَابٌ) → كِتَابًا (nashab/objek قَرَأْتُ كِتَابًا) → كِتَابٍ (jar فِي كِتَابٍ). Isim tidak bisa dijazm, fi''il tidak bisa dijar — aturan mutlak.', NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'jurumiyah' AND bab_order = 2;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 2, 'Marfu''at (7) & Mansubat (15)', 'الْمَرْفُوعَاتُ وَالْمَنْصُوبَاتُ', 'الْمَرْفُوعَاتُ سَبْعَةٌ: الْفَاعِلُ، وَالْمَفْعُولُ الَّذِي لَمْ يُسَمَّ فَاعِلُهُ، وَالْمُبْتَدَأُ، وَخَبَرُهُ، وَاسْمُ كَانَ، وَخَبَرُ إِنَّ، وَالتَّابِعُ لِلْمَرْفُوعِ. وَالْمَنْصُوبَاتُ خَمْسَةَ عَشَرَ.', 'Yang rafa'' (7): fa''il, naibul fa''il, mubtada'', khabar mubtada'', isim kana, khabar inna, tabi'' rafa''. Yang nashab (15): maf''ul bih, mashdar, zharaf zaman, zharaf makan, hal, tamyiz, mustatsna, isim la, munada, khabar kana, isim inna, tabi'' nashab.', 'Fa''il = pelaku aktif (رَفَعَ زَيْدٌ). Naibul fa''il = subjek pasif (رُفِعَ زَيْدٌ). Mubtada''-khabar = subjek-predikat kalimat nominal (زَيْدٌ قَائِمٌ). Maf''ul bih = objek (ضَرَبَ زَيْدٌ عَمْرًا).', NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'jurumiyah' AND bab_order = 2;

INSERT OR IGNORE INTO pesantren_kitab (slug, category_slug, title_ar, title_id, author, author_death_year, description_id, sort_order) VALUES ('imrithi', 'nahwu-shorof', 'نَظْمُ الْإِمْرِيطِيِّ', 'Al-Imrithi', 'Syaikh Syarafuddin Yahya Al-Imrithi', NULL, 'Nadhom 250 bait — syarah Al-Jurumiyyah dalam format mudah dihafal', 12);
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('imrithi', 1, 'Muqaddimah & Kalam', 'الْمُقَدِّمَةُ وَالْكَلَامُ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, 'Pembukaan & Tujuan Belajar Nahwu', 'مَطْلَعُ النَّظْمِ', 'يَقُولُ رَاجِي رَحْمَةِ الرَّبِّ الصَّمَدْ *** يَحْيَى عِمْرِيطِيٌّ عَلَى هَذَا اعْتَمَدْ
وَالْحَمْدُ لِلَّهِ الَّذِي عَلَّمَنَا *** عِلْمَ النَّحْوِ وَبِهِ فَهَّمَنَا
إِنَّ الْكَلَامَ عِنْدَنَا لَفْظٌ مُفِيدْ *** كَجَاءَ زَيْدٌ وَاضْحَكَ الْبَشِيرُ زَيْدْ', 'Berkata orang yang mengharap rahmat Allah Ash-Shamad: Yahya Al-Imrithi — atas inilah ia bersandar. Segala puji bagi Allah yang mengajari kami nahwu dan melaluinya kami memahami. Kalam menurut kami adalah lafazh yang mengandung faedah — seperti ''Zaid datang'' dan ''Zaid membuat si pembawa kabar tertawa''.', 'Al-Imrithi menggubah nadhom untuk memudahkan hafalan Jurumiyyah. Tujuan mulia: belajar nahwu untuk memahami Al-Qur''an dan Hadits. ''Rajiy rahmatir rabbish-shamad'' = rendah hati khas ulama. Dua contoh kalam yang elegan: kalimat pendek namun sempurna maknanya.', NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'imrithi' AND bab_order = 1;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 2, 'Nadhom I''rab & Asmaul Khamsah', 'الْإِعْرَابُ وَالْأَسْمَاءُ الْخَمْسَةُ', 'وَالْإِعْرَابُ تَغْيِيرٌ يَلْحَقُ الْأَوَاخِرَا *** مِنَ الْكَلِمِ لِاخْتِلَافِ الْعَوَامِلَا
وَارْفَعْ بِوَاوٍ وَانْصِبَنَّ بِالْأَلِفِ *** وَاخْفِضْ بِيَاءٍ أَبٌ أَخٌ حَمٌ وَفُو وَذُو', 'I''rab = perubahan akhir kata karena amil. Asmaul khamsah (5 isim khusus): Ab, Akh, Ham, Fu, Dzu — rafa'' dengan waw (أَبُوكَ), nashab dengan alif (أَبَاكَ), jar dengan ya'' (أَبِيكَ).', 'Asmaul khamsah memiliki tanda i''rab huruf (bukan harakat). Syarat: tunggal, mudhaf (bersambung dengan kata lain), mudhaf ilaih bukan ya'' mutakallim. Contoh: أَبُوكَ كَرِيمٌ (ayahmu mulia) → أَبُوكَ rafa'' dengan waw.', NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'imrithi' AND bab_order = 1;

INSERT OR IGNORE INTO pesantren_kitab (slug, category_slug, title_ar, title_id, author, author_death_year, description_id, sort_order) VALUES ('alfiyah', 'nahwu-shorof', 'أَلْفِيَّةُ ابْنِ مَالِكٍ', 'Alfiyah Ibnu Malik', 'Imam Ibnu Malik Al-Andalusi', '672H', '1002 bait nadhom nahwu-shorof — puncak ilmu nahwu pesantren', 13);
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('alfiyah', 1, 'Muqaddimah & Kalam', 'الْمُقَدِّمَةُ وَالْكَلَامُ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, 'Bait 1-5: Pembukaan Alfiyah', 'مَطْلَعُ الْأَلْفِيَّةِ', 'قَالَ مُحَمَّدٌ هُوَ ابْنُ مَالِكِ *** أَحْمَدُ رَبِّيَ اللهَ خَيْرَ مَالِكِ
مُصَلِّيًا عَلَى النَّبِيِّ الْمُصْطَفَى *** وَآلِهِ الْمُسْتَكْمِلِينَ الشَّرَفَا
وَأَسْتَعِينُ اللهَ فِي أَلْفِيَّةْ *** مَقَاصِدُ النَّحْوِ بِهَا مَحْوِيَّةْ', 'Berkata Muhammad — Ibnu Malik: Aku memuji Allah. Bershalawat atas Nabi Al-Mushthafa dan keluarganya. Aku memohon pertolongan Allah dalam Alfiyah ini — yang di dalamnya terkandung semua tujuan ilmu nahwu.', 'Alfiyah Ibnu Malik (1002 bait) adalah mahakarya nahwu yang merangkum Sibawaih hingga ulama ahli bahasa. ''Maqashidun-nahwi biha mahwiyyah'' = semua tujuan nahwu ada di sini. Santri yang hafal dan paham dianggap ahli nahwu.', NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'alfiyah' AND bab_order = 1;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 2, 'Bait 6-10: Kalam, Kalim, Isim', 'الْكَلَامُ وَالِاسْمُ', 'كَلَامُنَا لَفْظٌ مُفِيدٌ كَاسْتَقِمْ *** وَاسْمٌ وَفِعْلٌ ثُمَّ حَرْفٌ الْكَلِمْ
بِالْجَرِّ وَالتَّنْوِينِ وَالنِّدَا وَأَلْ *** وَمُسْنَدٍ لِلِاسْمِ تَمْيِيزٌ حَصَلْ', 'Kalam = lafazh yang mengandung faedah seperti ''Istikim!''. Kalim = isim, fi''il, harf. Isim dibedakan dengan: jar, tanwin, nida'', alif-lam, dan dijadikan sandaran (musnad ilaih).', 'Ibnu Malik menambahkan ''nida'''' (يَا زَيْدُ) dan ''musnad ilaih'' (dijadikan subjek) sebagai tanda isim — lebih lengkap dari Jurumiyyah. ''Istikim!'' = satu kata namun kalam sempurna karena perintah yang jelas.', NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'alfiyah' AND bab_order = 1;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('alfiyah', 2, 'Fa''il & Mubtada''-Khabar', 'الْفَاعِلُ وَالْمُبْتَدَأُ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, 'Bab Fa''il', 'بَابُ الْفَاعِلِ', 'الْفَاعِلُ الَّذِي كَمَرْفُوعَيْ أَتَى *** زَيْدٌ مُنِيرًا وَجْهُهُ نِعْمَ الْفَتَى
وَبَعْدَ فِعْلٍ فَاعِلٌ فَإِنْ ظَهَرْ *** فَهْوَ وَإِلَّا فَضَمِيرٌ اسْتَتَرْ', 'Fa''il datang dalam keadaan rafa''. Setelah fi''il, fa''il mengikut — jika tampak itulah fa''il, jika tidak ada dhamir mustatir (tersembunyi).', 'Fa''il = pelaku aktif, selalu rafa''. قَامَ زَيْدٌ → زَيْدٌ fa''il. Dhamir mustatir: قُمْتُ → fa''il = أَنَا mustatir. قَامَ → fa''il = هُوَ mustatir. Konsep ini kunci i''rab kalimat Arab.', NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'alfiyah' AND bab_order = 2;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 2, 'Mubtada''-Khabar & Nawasikh (Kana-Inna)', 'الْمُبْتَدَأُ وَالْخَبَرُ', 'مُبْتَدَأٌ زَيْدٌ وَعَاذِرٌ خَبَرْ *** إِنْ قُلْتَ زَيْدٌ عَاذِرٌ مَنِ اعْتَذَرْ
تَرْفَعُ كَانَ الْمُبْتَدَا اسْمًا وَالْخَبَرْ *** تَنْصِبُهُ كَكَانَ سَيِّدًا عُمَرْ', 'Mubtada'' rafa'', khabar rafa''. Kana merafa''kan mubtada'' (jadi isim kana) dan menashabkan khabar (jadi khabar kana) — كَانَ عُمَرُ سَيِّدًا.', 'Jumlah ismiyyah: مُحَمَّدٌ رَسُولُ اللهِ → mubtada''-khabar, keduanya rafa''. Kana mengubah hukum: isim kana tetap rafa'', khabar kana menjadi nashab. Saudara kana: أَصْبَحَ، أَمْسَى، صَارَ، لَيْسَ، مَا زَالَ, dll. Inna sebaliknya: isim inna nashab, khabar rafa''.', NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'alfiyah' AND bab_order = 2;

